class Bad {
    fun isLong(sb: StringBuilder): Boolean {
        return sb.toString().length > 100
    }
}

class Bad {
    fun isEmpty(sb: StringBuffer): Boolean {
        return sb.toString().length == 0
    }
}

class Good {
    fun isLong(sb: StringBuilder): Boolean {
        return sb.length > 100
    }
}

class Good {
    fun build(sb: StringBuilder): String {
        return sb.toString()
    }
}

class Good {
    fun strLen(s: String): Int {
        return s.length
    }
}
